Case ID: {{ $json.case_id }}
Submitted by Clerk: {{ $json.submitted_by || "Unknown" }}
Timestamp: {{ $json.timestamp }}

CLIENT PROFILE:
Name: {{ $json.user_name }}
Contact: {{ $json.contact_number || "Not provided" }}
Date of Birth: {{ $json.date_of_birth || "Not provided" }}
Civil Status: {{ $json.civil_status || "Not provided" }}
Address: {{ $json.address || "Not provided" }}
Occupation: {{ $json.occupation || "Not provided" }}

CASE CLASSIFICATION (from Intake Agent):
Legal Topic: {{ $json.legal_topic || "Unclassified" }}
Specific Legal Issue: {{ $json.legal_issue || "Not specified" }}
Incident Date: {{ $json.incident_date || "Not provided" }}
Opposing Party: {{ $json.opposing_party || "Not identified" }}
Urgency: {{ $json.urgency || "MEDIUM" }}

AI SUMMARY (from Intake Agent):
{{ $json.ai_summary || "No summary available." }}

CASE THEORY (from Intake Agent):
{{ $json.case_theory || "Not yet determined." }}

RAW CLIENT NARRATIVE (original clerk notes — treat this as primary source):
{{ $json.legal_narrative || "No narrative provided." }}

DOCUMENTS ALREADY IN HAND:
{{ $json.documents_submitted && $json.documents_submitted.length > 0 ? $json.documents_submitted.join(", ") : "None submitted yet" }}

DOCUMENTS STILL NEEDED (flagged by Intake Agent):
{{ $json.documents_needed && $json.documents_needed.length > 0 ? $json.documents_needed.join(", ") : "None flagged" }}

CLERK NOTES:
{{ $json.clerk_notes || "None." }}

Analyze this case. Build the strongest possible legal argument for the client. Return ONLY valid JSON.

parameters.jsCode:
// LexFlow — Lawyer A Parser (CORRECTED)
// Preserves all fields needed by dashboard

const item = $input.first().json;
const intake = $('Advocate Webhook1').item.json.body || $('Advocate Webhook1').item.json;
const raw = (item.output || item.text || item.response || "").toString().trim();

if (!raw) {
  return [{
    json: {
      ...intake,
      lawyer_a: {
        case_assessment: "AI analysis unavailable. Check Ollama is running.",
        legal_arguments: [],
        recommended_strategy: "PENDING",
        strategy_reasoning: "",
        settlement_viability: "UNKNOWN",
        settlement_notes: "",
        evidence_gaps: [],
        win_probability: "UNKNOWN",
        win_probability_notes: ""
      },
      lawyer_a_processed: false,
      lawyer_a_error: "Empty response from model",
      lawyer_a_raw: "",
      pipeline_status: 'ADVOCATE_FAILED'
    }
  }];
}

let cleaned = raw
  .replace(/```json\s*/gi, "")
  .replace(/```\s*/gi, "")
  .trim();

const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
if (jsonMatch) cleaned = jsonMatch[0];

let ai;
try {
  ai = JSON.parse(cleaned);
} catch (e) {
  return [{
    json: {
      ...intake,
      lawyer_a: {
        case_assessment: "JSON parse failed. See lawyer_a_raw.",
        legal_arguments: [],
        recommended_strategy: "PARSE_ERROR",
        strategy_reasoning: "",
        settlement_viability: "UNKNOWN",
        settlement_notes: "",
        evidence_gaps: [],
        win_probability: "UNKNOWN",
        win_probability_notes: ""
      },
      lawyer_a_processed: false,
      lawyer_a_error: "JSON.parse failed: " + e.message,
      lawyer_a_raw: raw,
      pipeline_status: 'ADVOCATE_FAILED'
    }
  }];
}

// Ensure required strategy values
const validStrategies = ['SETTLE', 'TRIAL', 'DEMAND_LETTER', 'MEDIATION', 'ADMINISTRATIVE_COMPLAINT', 'URGENT_PROTECTION_ORDER'];
const strategy = validStrategies.includes(ai.recommended_strategy) ? ai.recommended_strategy : 'PENDING';

return [{
  json: {
    // Preserve all original intake fields (critical for downstream)
    case_id:             intake.case_id,
    timestamp:           intake.timestamp,
    submitted_by:        intake.submitted_by,
    user_name:           intake.user_name,
    contact_number:      intake.contact_number   || "",
    date_of_birth:       intake.date_of_birth    || "",
    civil_status:        intake.civil_status     || "",
    address:             intake.address          || "",
    occupation:          intake.occupation       || "",
    legal_topic:         intake.legal_topic      || "",
    legal_issue:         intake.legal_issue      || "",
    incident_date:       intake.incident_date    || "",
    opposing_party:      intake.opposing_party   || "",
    urgency:             intake.urgency          || "MEDIUM",
    legal_narrative:     intake.legal_narrative  || "",
    clerk_notes:         intake.clerk_notes      || "",
    ai_summary:          intake.ai_summary       || "",
    case_theory:         intake.case_theory      || "",
    documents_submitted: intake.documents_submitted || [],
    documents_needed:    intake.documents_needed    || [],
    attachments_meta:    intake.attachments_meta   || [],
    document_urls:       intake.document_urls      || [],

    // Lawyer A analysis
    lawyer_a: {
      case_assessment:       ai.case_assessment       || "",
      legal_arguments:       ai.legal_arguments       || [],
      recommended_strategy:  strategy,
      strategy_reasoning:    ai.strategy_reasoning    || "",
      settlement_viability:  ai.settlement_viability  || "UNKNOWN",
      settlement_notes:      ai.settlement_notes      || "",
      evidence_gaps:         ai.evidence_gaps         || [],
      win_probability:       ai.win_probability       || "UNKNOWN",
      win_probability_notes: ai.win_probability_notes || ""
    },

    lawyer_a_processed: true,
    lawyer_a_error:     null,
    lawyer_a_raw:       raw,
    pipeline_status:    'ADVOCATE_COMPLETE'
  }
}];
